sp_widget.client_script:
function ($scope, $rootScope, amb, spUtil) {
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// WIDGET BASE: FIELDS
//------------------------------------------------------------------------------------------------------------------------
var c = this;

	loadReportWidget();
function loadReportWidget(){

	var query = c.data.filter;

	var mobileReportOptions = {
		"widget_parameters": { 

			"sysparm_query": query,
			"query": query,
			"filter": query
		}
	};
/*
			"sysparm_query": query
			"report_id": { "value": "", "displayValue": "" }, 
			"show_title": { "value": "false", "displayValue": "false" },			

			var params = { "jvar_report_id": reportId,
						 "sysparm_query":"primary_assignee='aa'"};
*/
	c.data.mobileReportWidget = null;
	spUtil.get('e2855785db851410dd0cdbdb5e96191a',mobileReportOptions).then(function(response) {
			c.data.mobileReportWidget = response;
		});						

	}	
}

