(function($sp, input, data, options, gs) {
	data.page_id = (input || {}).page_id || (options || {}).page_id;
	data.title = (input || {}).title || (options || {}).title;
	data.filter = (input || {}).filter || (options || {}).filter;
	data.reportListFilter = (input || {}).reportListFilter || (options || {}).reportListFilter;

	data.table = (input || {}).table || (options || {}).table;

	var reportListOptions = {
		"active": true,
		"color": "primary",
		"enable_filter": { "value": "false", "displayValue": "false"},
		"open_row_details_in_modal": {"value": "false","displayValue": "false"},
		"display_field": "title",
		"field_list": "title",
		"glyph": "pie-chart",
		"table": data.table,
		"filter": data.reportListFilter
	};
	data.reportListWidget = $sp.getWidget('discovertasker-widget-data-table', reportListOptions);	

//	var mobileReportOptions = { 
//		"report_id": { "value": "", "displayValue": "" }, 
//		"show_title": { "value": "false", "displayValue": "false" } 
//	};
//	data.mobileReportWidget = $sp.getWidget('e2855785db851410dd0cdbdb5e96191a', mobileReportOptions);	

	//var pageWidgetOptions = {"page_id":"organizational_report_page", "type_id": "2f49aa5ddbabf7800f34fcfa0c961978"};
	//data.pageWidget = $sp.getWidget('organizational_report_page', pageWidgetOptions);	
})($sp, input, data, options, gs);
